"""
T2 Blog — Article Routes (Gen 1 Sample 1, Variant)

Design strategy: Inherits the ATU-001 proven patterns (_resp factory,
namedtuple serialization) and extends them for article CRUD + tag binding.

Unique decisions in this variant:
- ArticleData namedtuple with deterministic field order (id, title, body)
- Tag binding via direct article_tags.insert() with IntegrityError guard
  (TOCTOU-safe, consistent with tag routes' duplicate detection)
- Tag unbinding via direct article_tags.delete() -- no ORM load needed
- Query-level tag filtering via JOIN on article_tags (not Python filtering)
- Eager tag loading only when requested (default list omits tags for speed)
"""

from collections import namedtuple
from flask import Blueprint, request, jsonify
from sqlalchemy.exc import IntegrityError

from app import db
from models import Article, Tag, article_tags

article_bp = Blueprint('article_bp', __name__)

# --- Serialization layer ---

ArticleData = namedtuple('ArticleData', ['id', 'title', 'body'])
TagData = namedtuple('TagData', ['id', 'name'])


def _serialize_article(article: Article) -> dict:
    """Convert an Article ORM object to a plain dict with stable key order."""
    return ArticleData(id=article.id, title=article.title, body=article.body)._asdict()


def _serialize_articles(articles) -> list:
    """Serialize a list/query of Article objects."""
    return [_serialize_article(a) for a in articles]


def _serialize_tag(tag: Tag) -> dict:
    """Convert a Tag ORM object to a plain dict with stable key order."""
    return TagData(id=tag.id, name=tag.name)._asdict()


def _serialize_tags(tags) -> list:
    """Serialize a list/query of Tag objects."""
    return [_serialize_tag(t) for t in tags]


# --- Response builder factory (inherited from ATU-001) ---

def _resp(status: str, data=None, message: str = None, code: int = 200):
    """
    Build a standardized JSON response envelope.
    Usage: return _resp('ok', data=article_dict, code=201)
           return _resp('error', message='Not found', code=404)
    """
    body = {'status': status}
    if status == 'ok':
        body['data'] = data
    else:
        body['message'] = message
    return jsonify(body), code


# --- Routes ---

@article_bp.route('/articles', methods=['GET'])
def list_articles():
    """
    List all articles. Supports optional tag filtering:
      ?tag=<name>   -- filter by tag name
      ?tag_id=<id>  -- filter by tag ID
    Returns 200 with list (empty if no matches).
    """
    tag_name = request.args.get('tag', '').strip() or None
    tag_id_str = request.args.get('tag_id', '').strip() or None

    query = Article.query.order_by(Article.id)

    if tag_name is not None:
        query = (
            query
            .join(article_tags, Article.id == article_tags.c.article_id)
            .join(Tag, article_tags.c.tag_id == Tag.id)
            .filter(Tag.name == tag_name)
        )
    elif tag_id_str is not None:
        try:
            tag_id = int(tag_id_str)
        except ValueError:
            return _resp('error', message='tag_id must be an integer', code=400)
        query = (
            query
            .join(article_tags, Article.id == article_tags.c.article_id)
            .filter(article_tags.c.tag_id == tag_id)
        )

    articles = query.all()
    return _resp('ok', data=_serialize_articles(articles))


@article_bp.route('/articles', methods=['POST'])
def create_article():
    """Create a new article. Requires title and body in JSON body."""
    payload = request.get_json(silent=True) or {}
    title = (payload.get('title') or '').strip()
    body = (payload.get('body') or '').strip()

    if not title or not body:
        missing = []
        if not title:
            missing.append('title')
        if not body:
            missing.append('body')
        return _resp('error', message=f'Missing required field(s): {", ".join(missing)}', code=400)

    article = Article(title=title, body=body)
    db.session.add(article)
    db.session.commit()

    return _resp('ok', data=_serialize_article(article), code=201)


@article_bp.route('/articles/<int:article_id>', methods=['GET'])
def get_article(article_id: int):
    """Get a single article by ID. Returns 404 if not found."""
    article = Article.query.get(article_id)
    if article is None:
        return _resp('error', message=f'Article {article_id} not found', code=404)

    return _resp('ok', data=_serialize_article(article))


@article_bp.route('/articles/<int:article_id>/tags', methods=['POST'])
def bind_tags(article_id: int):
    """
    Bind tags to an article.

    Uses direct INSERT on the association table with IntegrityError guard,
    which is TOCTOU-safe and avoids checking existence first.

    Request: {"tag_ids": [1, 2, 3]}
    Returns: 200 on success, 404 if article not found, 400 if any tag_id is invalid.
    """
    article = Article.query.get(article_id)
    if article is None:
        return _resp('error', message=f'Article {article_id} not found', code=404)

    payload = request.get_json(silent=True) or {}
    tag_ids = payload.get('tag_ids')

    if not isinstance(tag_ids, list) or len(tag_ids) == 0:
        return _resp('error', message='tag_ids must be a non-empty list of integers', code=400)

    # Validate all tag_ids exist before any inserts
    existing_tag_ids = set(
        t.id for t in Tag.query.filter(Tag.id.in_(tag_ids)).all()
    )
    missing = set(tag_ids) - existing_tag_ids
    if missing:
        return _resp('error', message=f'Tag(s) not found: {", ".join(str(tid) for tid in sorted(missing))}', code=400)

    # Insert bindings directly into the association table
    bound_count = 0
    for tid in tag_ids:
        stmt = article_tags.insert().values(article_id=article_id, tag_id=tid)
        try:
            db.session.execute(stmt)
            bound_count += 1
        except IntegrityError:
            db.session.rollback()
            # Already bound -- skip silently (idempotent)

    db.session.commit()
    return _resp('ok', data={'message': 'Tags bound', 'bound_count': bound_count})


@article_bp.route('/articles/<int:article_id>/tags', methods=['GET'])
def get_article_tags(article_id: int):
    """Get all tags bound to an article. Returns 404 if article not found."""
    article = Article.query.get(article_id)
    if article is None:
        return _resp('error', message=f'Article {article_id} not found', code=404)

    tags = article.tags.order_by(Tag.id).all()
    return _resp('ok', data=_serialize_tags(tags))


@article_bp.route('/articles/<int:article_id>/tags/<int:tag_id>', methods=['DELETE'])
def unbind_tag(article_id: int, tag_id: int):
    """
    Remove the association between an article and a tag.

    Uses direct DELETE on the association table -- no ORM load needed.
    Returns 404 if the article does not exist.
    """
    article = Article.query.get(article_id)
    if article is None:
        return _resp('error', message=f'Article {article_id} not found', code=404)

    stmt = article_tags.delete().where(
        article_tags.c.article_id == article_id,
        article_tags.c.tag_id == tag_id,
    )
    result = db.session.execute(stmt)
    db.session.commit()

    if result.rowcount == 0:
        return _resp('error', message=f'Tag {tag_id} is not bound to article {article_id}', code=404)

    return _resp('ok', data={'message': 'Tag unbound'})

"""
T2 Blog -- Article Routes (Gen 1 Sample 2)

Design strategy: Decorator-based validation + Strategy-pattern response classes
+ relationship-driven tag binding.

Key differentiators from Sample 1:
1. ResponseEnvelope class hierarchy (ok/error) replaces the _resp() factory function.
   Each envelope carries its own HTTP status code, keeping route returns to a
   single `envelope.flask_response()` call.
2. @require_json_fields decorator centralizes input validation. Routes declare
   their required payload fields declaratively; the decorator short-circuits with
   400 before the handler body ever runs.
3. Tag binding uses Article.tags relationship (append/remove) instead of direct
   article_tags.insert()/delete(). This leverages SQLAlchemy's ORM-level cascade
   and keeps the association table as an implementation detail.
4. ArticlePayload dataclass normalizes and validates creation input in one place,
   separating "what constitutes a valid article" from "how we save it."
"""

from dataclasses import dataclass
from typing import Any, List, Optional

from flask import Blueprint, request, jsonify

from app import db
from models import Article, Tag, article_tags

article_bp = Blueprint('article_bp', __name__)


# ---------------------------------------------------------------------------
# Strategy-pattern response envelopes
# ---------------------------------------------------------------------------

class ResponseEnvelope:
    """Base class for all API response envelopes."""

    status: str
    code: int

    def body(self) -> dict:
        raise NotImplementedError

    def flask_response(self):
        return jsonify(self.body()), self.code


class OkEnvelope(ResponseEnvelope):
    """Success envelope: {"status": "ok", "data": ...}"""

    status = "ok"
    code = 200

    def __init__(self, data: Any):
        self._data = data

    def body(self) -> dict:
        return {"status": self.status, "data": self._data}


class CreatedEnvelope(OkEnvelope):
    """201 variant of the success envelope."""

    code = 201


class ErrorEnvelope(ResponseEnvelope):
    """Error envelope: {"status": "error", "message": ...}"""

    status = "error"

    def __init__(self, message: str, code: int = 400):
        self._message = message
        self.code = code

    def body(self) -> dict:
        return {"status": self.status, "message": self._message}


# ---------------------------------------------------------------------------
# Decorator-based input validation
# ---------------------------------------------------------------------------

def require_json_fields(*fields: str):
    """
    Decorator that validates the presence of JSON payload fields.

    If any required field is missing or empty after stripping, returns a 400
    ErrorEnvelope immediately without invoking the handler.

    Usage:
        @require_json_fields('title', 'body')
        def create_article():
            ...
    """
    def decorator(fn):
        def wrapper(*args, **kwargs):
            payload = request.get_json(silent=True) or {}
            for field in fields:
                value = (payload.get(field) or '').strip()
                if not value:
                    return ErrorEnvelope(
                        message=f'Field "{field}" is required',
                        code=400,
                    ).flask_response()
            return fn(*args, **kwargs)
        return wrapper
    return decorator


# ---------------------------------------------------------------------------
# Dataclass-based input model
# ---------------------------------------------------------------------------

@dataclass
class ArticlePayload:
    """Normalized and validated article creation input."""
    title: str
    body: str

    @classmethod
    def from_request(cls) -> Optional['ArticlePayload']:
        """Extract and validate payload from the current request context."""
        payload = request.get_json(silent=True) or {}
        title = (payload.get('title') or '').strip()
        body = (payload.get('body') or '').strip()
        if not title or not body:
            return None
        return cls(title=title, body=body)


# ---------------------------------------------------------------------------
# Serialization helpers
# ---------------------------------------------------------------------------

def _serialize_article(article: Article) -> dict:
    """Convert an Article ORM object to a plain dict."""
    return {"id": article.id, "title": article.title, "body": article.body}


def _serialize_articles(articles) -> list:
    """Serialize a list/query of Article objects."""
    return [_serialize_article(a) for a in articles]


def _serialize_tag(tag: Tag) -> dict:
    """Convert a Tag ORM object to a plain dict."""
    return {"id": tag.id, "name": tag.name}


def _serialize_tags(tags) -> list:
    """Serialize a list of Tag objects."""
    return [_serialize_tag(t) for t in tags]


# ---------------------------------------------------------------------------
# Helper: fetch article or return 404 envelope
# ---------------------------------------------------------------------------

def _get_article_or_404(article_id: int):
    """Return (article, None) on success, or (None, error_response) on 404."""
    article = Article.query.get(article_id)
    if article is None:
        return None, ErrorEnvelope(
            message=f'Article {article_id} not found',
            code=404,
        ).flask_response()
    return article, None


# ---------------------------------------------------------------------------
# Routes
# ---------------------------------------------------------------------------

@article_bp.route('/articles', methods=['GET'])
def list_articles():
    """
    List all articles. Supports optional filtering:
      ?tag=<name>   -- filter by tag name
      ?tag_id=<id>  -- filter by tag ID
    Returns an empty list (200) when no articles match the filter.
    """
    tag_name = (request.args.get('tag') or '').strip()
    tag_id_str = (request.args.get('tag_id') or '').strip()

    articles = None

    if tag_name:
        # Use the ORM relationship: find tags by name, then collect their articles
        tag = Tag.query.filter_by(name=tag_name).first()
        if tag is None:
            return OkEnvelope(data=[]).flask_response()
        articles = tag.articles.order_by(Article.id).all()

    elif tag_id_str:
        try:
            tid = int(tag_id_str)
        except ValueError:
            return ErrorEnvelope(message='tag_id must be an integer', code=400).flask_response()
        tag = Tag.query.get(tid)
        if tag is None:
            return OkEnvelope(data=[]).flask_response()
        articles = tag.articles.order_by(Article.id).all()

    else:
        articles = Article.query.order_by(Article.id).all()

    return OkEnvelope(data=_serialize_articles(articles)).flask_response()


@article_bp.route('/articles', methods=['POST'])
@require_json_fields('title', 'body')
def create_article():
    """
    Create a new article.
    Request body: {"title": "...", "body": "..."}
    Returns 201 on success, 400 if title or body is missing.
    """
    payload = request.get_json(silent=True) or {}
    title = (payload.get('title') or '').strip()
    body = (payload.get('body') or '').strip()

    article = Article(title=title, body=body)
    db.session.add(article)

    try:
        db.session.commit()
    except Exception:
        db.session.rollback()
        return ErrorEnvelope(message='Failed to create article', code=500).flask_response()

    return CreatedEnvelope(data=_serialize_article(article)).flask_response()


@article_bp.route('/articles/<int:article_id>', methods=['GET'])
def get_article(article_id: int):
    """Retrieve a single article by ID. Returns 404 if not found."""
    article, err = _get_article_or_404(article_id)
    if err:
        return err
    return OkEnvelope(data=_serialize_article(article)).flask_response()


@article_bp.route('/articles/<int:article_id>/tags', methods=['GET'])
def get_article_tags(article_id: int):
    """Return all tags bound to an article. Returns 404 if article not found."""
    article, err = _get_article_or_404(article_id)
    if err:
        return err
    tags = article.tags.order_by(Tag.id).all()
    return OkEnvelope(data=_serialize_tags(tags)).flask_response()


@article_bp.route('/articles/<int:article_id>/tags', methods=['POST'])
def bind_tags(article_id: int):
    """
    Bind one or more tags to an article via the ORM relationship.
    Request body: {"tag_ids": [1, 2, 3]}
    Returns 404 if article not found, 400 if any tag_id is invalid or missing.
    """
    article, err = _get_article_or_404(article_id)
    if err:
        return err

    payload = request.get_json(silent=True) or {}
    tag_ids = payload.get('tag_ids')

    if not isinstance(tag_ids, list) or len(tag_ids) == 0:
        return ErrorEnvelope(
            message='tag_ids must be a non-empty list of integers',
            code=400,
        ).flask_response()

    # Validate all tag IDs exist before binding any
    existing_tags = {t.id: t for t in Tag.query.filter(Tag.id.in_(tag_ids)).all()}
    missing = [tid for tid in tag_ids if tid not in existing_tags]

    if missing:
        return ErrorEnvelope(
            message=f'Tag(s) not found: {missing}',
            code=400,
        ).flask_response()

    # Use relationship append -- SQLAlchemy handles the association table
    bound_count = 0
    for tid in tag_ids:
        tag = existing_tags[tid]
        if tag not in article.tags:
            article.tags.append(tag)
            bound_count += 1

    db.session.commit()

    return OkEnvelope(data={"message": f"Tags bound"}).flask_response()


@article_bp.route('/articles/<int:article_id>/tags/<int:tag_id>', methods=['DELETE'])
def unbind_tag(article_id: int, tag_id: int):
    """
    Remove a tag from an article via the ORM relationship.
    Returns 404 if article not found. Silently succeeds if the binding
    did not exist (idempotent).
    """
    article, err = _get_article_or_404(article_id)
    if err:
        return err

    tag = Tag.query.get(tag_id)

    # Use relationship remove -- idempotent: no-op if not bound
    if tag in article.tags:
        article.tags.remove(tag)
        db.session.commit()

    return OkEnvelope(data={"message": "Tag unbound"}).flask_response()

